/**
 * Telegram UI helpers — message formatting, splitting, ASK keyboards,
 * file sending, and token extraction for SEND_FILE / SCHEDULE / ASK.
 * Extracted from index.ts to reduce its size.
 */
import { InlineKeyboard, Context, InputFile } from "grammy";
import path from "node:path";
import { stat } from "node:fs/promises";
import { config } from "./config.js";
import type { ChatSession } from "./sessionManager.js";
import { toolPrefixLines } from "./sessionManager.js";
import { transform as transformReplyTokens } from "./observerTransformer.js";
import type { Recurrence } from "./recurrence.js";
import { markdownToHtml } from "./format-html.js";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------
const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
const SEND_FILE_RE = /<<SEND_FILE:\s*([^>\r\n]+?)\s*>>/g;
const SCHEDULE_RE = /<<SCHEDULE:\s*([^>\r\n]+?)\s*>>/g;
const SCHEDULE_PROMPT_MAX = 1000;
const SCHEDULE_MAX_PER_MSG = 3;
const ASK_RE = /<<ASK:\s*([^>\r\n]+?)\s*>>/g;
const ASK_ID_RE = /^[a-zA-Z0-9_-]{1,32}$/;
const ASK_KEY_RE = /^[a-zA-Z0-9_-]{1,20}$/;
const ASK_LABEL_MAX = 40;
const ASK_LABEL_SOFT = 20;
export const IMG_EXT = new Set([".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp"]);
export const TG_MAX = 3900;

// ---------------------------------------------------------------------------
// Interfaces
// ---------------------------------------------------------------------------
export interface AskOption {
  key: string;
  label: string;
  recommended: boolean;
}

export interface AskEntry {
  questionId: string;
  options: AskOption[];
}

export interface ScheduleTokenEntry {
  runAt: number;
  prompt: string;
  whenLabel: string;
  recurrence?: Recurrence;
}

export interface PendingSchedule {
  userId: number;
  kind: "add" | "at" | "every" | "daily";
  time: string;
  createdAt: number;
}

/** Parsers injected by caller to avoid circular deps */
export interface ScheduleParsers {
  parseDuration: (s: string) => number | null;
  parseAbsoluteTime: (s: string) => Date | null;
  parseRecurrence: (s: string) => Recurrence | null;
  computeNextRunAt: (r: Recurrence, after: number) => number | null;
}

// ---------------------------------------------------------------------------
// Code-block masking
// ---------------------------------------------------------------------------
export function maskCodeRegions(text: string): { masked: string; restore: (s: string) => string } {
  const slots: string[] = [];
  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
    const idx = slots.length;
    slots.push(m);
    return `\u0000CODE${idx}\u0000`;
  });
  const restore = (s: string) =>
    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
  return { masked, restore };
}

// ---------------------------------------------------------------------------
// SEND_FILE token extraction
// ---------------------------------------------------------------------------
export function extractSendFileTokens(text: string): { text: string; paths: string[] } {
  if (!text) return { text: "", paths: [] };
  const paths: string[] = [];
  const { masked, restore } = maskCodeRegions(text);
  const stripped = masked.replace(SEND_FILE_RE, (_m, p: string) => {
    paths.push(p.trim());
    return "";
  });
  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
  return { text: cleaned, paths };
}

// ---------------------------------------------------------------------------
// SCHEDULE token extraction
// ---------------------------------------------------------------------------
export function extractScheduleTokens(
  text: string,
  parsers: ScheduleParsers,
): { text: string; entries: ScheduleTokenEntry[] } {
  if (!text) return { text: "", entries: [] };
  const entries: ScheduleTokenEntry[] = [];
  const { masked, restore } = maskCodeRegions(text);
  const stripped = masked.replace(SCHEDULE_RE, (match, inner: string) => {
    if (entries.length >= SCHEDULE_MAX_PER_MSG) return match;
    const pipe = inner.indexOf("|");
    if (pipe <= 0) return match;
    const timeRaw = inner.slice(0, pipe).trim();
    let prompt = inner.slice(pipe + 1).trim();
    if (!prompt) return match;
    if (prompt.length > SCHEDULE_PROMPT_MAX) {
      prompt = prompt.slice(0, SCHEDULE_PROMPT_MAX);
    }
    const now = Date.now();
    const recurrence = parsers.parseRecurrence(timeRaw);
    if (recurrence) {
      const firstRunAt = parsers.computeNextRunAt(recurrence, now - 1);
      if (firstRunAt === null) return match;
      entries.push({ runAt: firstRunAt, prompt, whenLabel: timeRaw, recurrence });
      return "";
    }
    let runAt: number | null = null;
    const dur = parsers.parseDuration(timeRaw);
    if (dur !== null) {
      runAt = now + dur;
    } else {
      const dt = parsers.parseAbsoluteTime(timeRaw);
      if (dt && dt.getTime() > now) runAt = dt.getTime();
    }
    if (runAt === null) return match;
    entries.push({ runAt, prompt, whenLabel: timeRaw });
    return "";
  });
  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
  return { text: cleaned, entries };
}

// ---------------------------------------------------------------------------
// ASK token extraction & keyboard
// ---------------------------------------------------------------------------
export function extractAskTokens(text: string): { text: string; asks: AskEntry[] } {
  if (!text) return { text: "", asks: [] };
  const asks: AskEntry[] = [];
  const seenIds = new Set<string>();
  const { masked, restore } = maskCodeRegions(text);
  const stripped = masked.replace(ASK_RE, (match, inner: string) => {
    const entry = parseAskInner(inner);
    if (!entry) return match;
    if (seenIds.has(entry.questionId)) {
      const idx = asks.findIndex((a) => a.questionId === entry.questionId);
      if (idx >= 0) asks.splice(idx, 1);
    }
    seenIds.add(entry.questionId);
    asks.push(entry);
    return "";
  });
  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
  return { text: cleaned, asks };
}

function parseAskInner(inner: string): AskEntry | null {
  const reject = (reason: string): null => {
    const preview = inner.length > 80 ? `${inner.slice(0, 77)}...` : inner;
    console.warn(`[ASK] malformed token rejected: ${reason} | inner="${preview}"`);
    return null;
  };
  const parts = inner.split("|").map((s) => s.trim());
  if (parts.length < 2) return reject("need at least question_id + 1 option");
  const questionId = parts[0];
  if (!ASK_ID_RE.test(questionId)) {
    return reject(
      `question_id "${questionId}" invalid (need [a-zA-Z0-9_-]{1,32}, got length ${questionId.length})`
    );
  }
  const options: AskOption[] = [];
  const keys = new Set<string>();
  let recommendedCount = 0;
  for (const raw of parts.slice(1)) {
    if (!raw) continue;
    let spec = raw;
    let recommended = false;
    if (spec.startsWith("*")) {
      recommended = true;
      spec = spec.slice(1);
    }
    const eq = spec.indexOf("=");
    if (eq <= 0) return reject(`option "${raw}" missing "key=label"`);
    const key = spec.slice(0, eq).trim();
    const label = spec.slice(eq + 1).trim();
    if (!ASK_KEY_RE.test(key)) {
      return reject(
        `key "${key}" invalid (need [a-zA-Z0-9_-]{1,20}, got length ${key.length})`
      );
    }
    if (!label) return reject(`key "${key}" has empty label`);
    if (label.length > ASK_LABEL_SOFT && label.length <= ASK_LABEL_MAX) {
      console.warn(
        `[ASK] label soft cap exceeded (got ${label.length}, soft ${ASK_LABEL_SOFT}): key="${key}" label="${label}"`,
      );
    }
    if (label.length > ASK_LABEL_MAX) {
      return reject(
        `key "${key}" label too long (got ${label.length}, max ${ASK_LABEL_MAX}): "${label}"`
      );
    }
    if (keys.has(key)) return reject(`duplicate key "${key}"`);
    keys.add(key);
    if (recommended && recommendedCount > 0) recommended = false;
    if (recommended) recommendedCount++;
    options.push({ key, label, recommended });
  }
  if (options.length < 1) return reject("no valid options");
  if (options.length > 8) return reject(`too many options (got ${options.length}, max 8)`);
  return { questionId, options };
}

export function buildAskKeyboard(asks: AskEntry[]): InlineKeyboard | null {
  if (!asks.length) return null;
  const kb = new InlineKeyboard();
  for (let ai = 0; ai < asks.length; ai++) {
    const entry = asks[ai];
    const rows = layoutOptions(entry.options);
    for (const row of rows) {
      for (const opt of row) {
        const label = opt.recommended ? `⭐ ${opt.label}` : opt.label;
        kb.text(label, `A:${entry.questionId}:${opt.key}`);
      }
      kb.row();
    }
    const rec = entry.options.find((o) => o.recommended);
    if (rec) {
      kb.text("👉 照你的建議", `A:${entry.questionId}:${rec.key}`).row();
    }
  }
  return kb;
}

export function layoutOptions(options: AskOption[]): AskOption[][] {
  const n = options.length;
  if (n <= 3) return [options];
  if (n <= 6) {
    const perRow = Math.ceil(n / 2);
    return [options.slice(0, perRow), options.slice(perRow)];
  }
  const perRow = Math.ceil(n / 2);
  return [options.slice(0, perRow), options.slice(perRow)];
}

// In-memory registry: message_id -> ASK entries on that message.
export const askRegistry = new Map<number, AskEntry[]>();

export async function replyWithAsk(ctx: Context, text: string): Promise<void> {
  const { text: displayBody, asks } = extractAskTokens(text);
  const body = displayBody || text;
  const keyboard = buildAskKeyboard(asks);
  const msg = await ctx.reply(body, keyboard ? { reply_markup: keyboard } : {});
  if (keyboard && msg?.message_id !== undefined) {
    askRegistry.set(msg.message_id, asks);
  }
}

// ---------------------------------------------------------------------------
// askTimeKeyToWire / describePendingSchedule
// ---------------------------------------------------------------------------
export function askTimeKeyToWire(kind: PendingSchedule["kind"], key: string): string | null {
  if (kind === "add" || kind === "every") {
    return /^\d+(s|m|h|d)$/.test(key) ? key : null;
  }
  const mDirect = /^(\d{2})(\d{2})$/.exec(key);
  if (mDirect) return `${mDirect[1]}:${mDirect[2]}`;
  if (kind === "at") {
    const mTmr = /^tmr_(\d{2})(\d{2})$/.exec(key);
    if (mTmr) return `tomorrow ${mTmr[1]}:${mTmr[2]}`;
  }
  return null;
}

export function describePendingSchedule(kind: PendingSchedule["kind"], time: string): string {
  switch (kind) {
    case "add":   return `${time} 後（一次性）`;
    case "at":    return `${time}（一次性）`;
    case "every": return `每 ${time}`;
    case "daily": return `每天 ${time}`;
  }
}

// ---------------------------------------------------------------------------
// sendFilesByPaths / isUnderAllowedRoot
// ---------------------------------------------------------------------------
export async function sendFilesByPaths(ctx: Context, paths: string[]): Promise<number> {
  if (paths.length === 0) return 0;
  const chatId = ctx.chat?.id;
  const seen = new Set<string>();
  let sent = 0;
  for (const raw of paths) {
    const abs = path.resolve(raw);
    const key = abs.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    if (!isUnderAllowedRoot(abs)) {
      console.log(`[chat ${chatId}] SEND_FILE: refused (not under allowed roots): ${abs}`);
      continue;
    }
    try {
      const st = await stat(abs);
      if (!st.isFile()) {
        console.log(`[chat ${chatId}] SEND_FILE: skip (not a regular file): ${abs}`);
        continue;
      }
      const ext = path.extname(abs).toLowerCase();
      // .md → .txt display name: Telegram in-app viewer 對 .md UTF-8 偵測不可靠，中文會亂碼
      const displayName = ext === ".md"
        ? path.basename(abs, ext) + ".txt"
        : undefined;
      const asPhoto = IMG_EXT.has(ext) && ext !== ".png" && st.size <= 10 * 1024 * 1024;
      if (asPhoto) {
        try {
          await ctx.replyWithPhoto(new InputFile(abs));
          console.log(`[chat ${chatId}] SEND_FILE: sent photo (${st.size}B): ${abs}`);
        } catch (err) {
          console.warn(`[chat ${chatId}] SEND_FILE: photo rejected, fallback to document:`, (err as Error).message);
          await ctx.replyWithDocument(new InputFile(abs, displayName));
        }
      } else {
        await ctx.replyWithDocument(new InputFile(abs, displayName));
        console.log(`[chat ${chatId}] SEND_FILE: sent document (${st.size}B): ${abs}`);
      }
      sent++;
    } catch (err) {
      console.warn(`[chat ${chatId}] SEND_FILE: failed ${abs} — ${(err as Error).message}`);
    }
  }
  return sent;
}

export function isUnderAllowedRoot(abs: string): boolean {
  const roots = [config.sessionCwd, ...config.sendFileRoots];
  const normAbs = path.resolve(abs).toLowerCase();
  return roots.some((root) => {
    const r = path.resolve(root).toLowerCase().replace(/[\\/]+$/, "");
    if (normAbs === r) return true;
    return normAbs.startsWith(r + "\\") || normAbs.startsWith(r + "/");
  });
}

// ---------------------------------------------------------------------------
// splitForTelegram
// ---------------------------------------------------------------------------
export function splitForTelegram(text: string, max = TG_MAX): string[] {
  if (text.length <= max) return [text];
  const raw: string[] = [];
  let rest = text;
  while (rest.length > max) {
    let cut = rest.lastIndexOf("\n\n", max);
    if (cut < max * 0.5) cut = rest.lastIndexOf("\n", max);
    if (cut < max * 0.5) cut = rest.lastIndexOf(" ", max);
    if (cut <= 0) cut = max;
    raw.push(rest.slice(0, cut));
    rest = rest.slice(cut).replace(/^[\n ]+/, "");
  }
  if (rest.length) raw.push(rest);

  const fenceRe = /^```([^\n`]*)\s*$/;
  const out: string[] = [];
  let openLang = "";
  for (let i = 0; i < raw.length; i++) {
    let piece = raw[i];
    if (openLang !== "") {
      piece = "```" + openLang + "\n" + piece;
    }
    const lines = piece.split("\n");
    let inside = false;
    let lang = "";
    for (const line of lines) {
      const m = line.match(fenceRe);
      if (!m) continue;
      if (!inside) {
        inside = true;
        lang = m[1] ?? "";
      } else {
        inside = false;
        lang = "";
      }
    }
    if (inside && i < raw.length - 1) {
      piece = piece + (piece.endsWith("\n") ? "" : "\n") + "```";
      openLang = lang;
    } else {
      openLang = "";
    }
    out.push(piece);
  }
  return out;
}

// ---------------------------------------------------------------------------
// renderReply (streaming display)
// ---------------------------------------------------------------------------
export interface RenderResult {
  content: string;
  parseMode: "HTML" | undefined;
}

export function renderReply(
  session: ChatSession,
  done: boolean,
  parsers: ScheduleParsers,
): RenderResult {
  const toolLines = toolPrefixLines(session);
  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
  const cursor = done ? "" : " ▍";
  const emptyFallback = () => {
    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
    const n = session.toolTimeline.length;
    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
  };

  // Show thinking progress during streaming (hide when done)
  let thinkingBlock = "";
  if (!done && session.thinkingBuffer) {
    // Show last ~200 chars of thinking as blockquote
    const t = session.thinkingBuffer;
    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
  }

  const raw = session.buffer || emptyFallback();
  const stripped = transformReplyTokens(raw, parsers).text;
  let body = stripped || emptyFallback();
  if (body.length > TG_MAX) {
    body = "…" + body.slice(-TG_MAX);
  }

  const plain = tools + thinkingBlock + body + cursor;
  const { html } = markdownToHtml(plain);
  return { content: html, parseMode: "HTML" };
}

